// Java 25 exam prep - Initializer blocks
// Learn: trace static and instance initializers before constructors finish.
class Account {
    private static int nextId;
    static {
        nextId = 100; // Static initializer runs once when Account is initialized.
    }
    private final int id;
    private final String owner;
    {
        id = nextId++;
    }
    Account(String owner) {
        this.owner = owner;
    }
    String label() { return owner + "#" + id; }
}
